### API Route pattern

```typescript
// app/api/admin/<section>/route.ts
import { NextRequest, NextResponse } from "next/server";
import fs from "fs";
import path from "path";

const CONTENT_PATH = path.join(process.cwd(), "content", "es.json");

export async function GET() {
  const data = JSON.parse(fs.readFileSync(CONTENT_PATH, "utf-8"));
  return NextResponse.json({ section: data.sectionKey });
}

export async function PUT(request: NextRequest) {
  const body = await request.json();
  const data = JSON.parse(fs.readFileSync(CONTENT_PATH, "utf-8"));
  // merge body into data at the right key
  data.sectionKey = { ...data.sectionKey, ...body };
  fs.writeFileSync(CONTENT_PATH, JSON.stringify(data, null, 2), "utf-8");
  return NextResponse.json({ success: true });
}
```

### Form client component

- Load current values via `useEffect` ‚Üí `GET /api/admin/<section>`
- Update local state on each input change
- On submit: `PUT /api/admin/<section>` with current form state
- Show green success banner / red error banner on response
- Auto-generate WhatsApp deep links when `ctaHref` is empty (encode the item name into the query string)

### Pitfall: TSX patch + partial reads

`read_file(path, limit=N)` returns a truncated view. If you then use `patch(old_string=...)` where `old_string` spans beyond that limit, the patch silently misses the context and applies a wrong diff. Fix: use `execute_code` to read files for full-text inspection before patching, OR read the file without limits.

